mapper.select:
select jq.id, jq.mode_id, jm.mode, jq.category_id, jc.category, jq.quotation, jq.created_date, jq.flag from job_quotation jq left join job_mode jm on jq.mode_id = jm.id left join job_category jc on jq.category_id = jc.id where jq.flag = #{flag}
and jq.mode_id = #{modeId}
and jq.category_id = #{categoryId}
order by jq.created_date desc, jq.id desc
